// Example 2: Building on the basics

interface Config {
  name: string;
  verbose: boolean;
}

class App {
  constructor(private config: Config) {}

  run(): void {
    if (this.config.verbose) {
      console.log(`Starting ${this.config.name}...`);
    }
    // Your code here
  }
}

const app = new App({ name: "TypeScript App", verbose: true });
app.run();
